SELECT PSATTRIB.SACODE, PSATTRIB.SATAG, PSATTRIB.SATAGTYPE, ATTRIBS.ATDESC FROM PSATTRIB JOIN ATTRIBS ON PSATTRIB.SATAG = ATTRIBS.ATTAG WHERE PSATTRIB.SATAGTYPE <> 2 AND PSATTRIB.SATAGTYPE <> 5;

