SELECT brands.Desc AS BRAND, main_groups.Desc AS MAIN_GROUP, sub_groups.Desc AS SUB_GROUP, sub_sub_groups.Desc AS SUB_SUB_GROUP, PRODUCT.DESC3, PRODUCT.DESC4, PRODUCT.DESC5, PRODUCTDESCLOOKUP.NIEAN, PRODUCTDESCLOOKUP.NILDESC AS long_description, PRODUCTDESCLOOKUP.NIBRAND, PRODUCTDESCLOOKUP.NIINGREDS, PRODUCTDESCLOOKUP.NIABV, PRODUCTDESCLOOKUP.NIMANUFNADD, PRODUCTDESCLOOKUP.NIORIGIN, PRODUCTDESCLOOKUP.NISTORAGE, PRODUCTDESCLOOKUP.NISTORAGETYPE, PRODUCTDESCLOOKUP.NINUTRITIONHTML, PRODUCTDESCLOOKUP.NIPREPUSAGE, PRODUCTDESCLOOKUP.NICOOKGUIDE, PRODUCTDESCLOOKUP.NICOOKCONCISE, PRODUCTDESCLOOKUP.unit_net_weight, PRODUCT.CODE, PRODUCT.CUNIT, PRODUCT.CUNITFAC, PRODUCT.UF_IBARCODE, PRODUCT.UF_O_BARCODE, PRODUCT.UF_PRE_PRICED, PRODUCT.MASSNET, PRODUCT.MASSGROSS, PRODUCT.VOL, PRODUCT.COMMOD, PRODUCT.UF_CATCHWT, PRODUCT.UF_CSSPALLET, PRODUCT.UF_CSSLAYER, PRODUCT.UF_BBEROTDATE, PRODUCT.UF_BBEROTDIS, PRODUCT.UF_RRP, PRODUCT.UF_WH_SHELF, PRODUCT.UF_NODISCOUNT, PRODUCT.PRUSER01, PRODUCT.PRUSER02, PRODUCT.PRUSER03, PRODUCT.UF_SUPPLIERSUB, PRODUCT.UF_RIALT1, PRODUCT.UF_RIALT2, PRODUCT.UF_RIALT3, PRODUCT.UF_RIALT4 FROM PRODUCT LEFT JOIN PRODGRP brands ON LEFT(PRODUCT.CODE, 1) + 'UK' = brands.Code LEFT JOIN PRODGRP main_groups ON LEFT(PRODUCT.GROUP, 2) + 'UK' = main_groups.Code LEFT JOIN PRODGRP sub_groups ON LEFT(PRODUCT.GROUP, 4) + 'UK' = sub_groups.Code LEFT JOIN PRODGRP sub_sub_groups ON LEFT(PRODUCT.GROUP, 6) + 'UK' = sub_sub_groups.Code LEFT JOIN PRODUCTDESCLOOKUP ON PRODUCT.UF_IBARCODE = PRODUCTDESCLOOKUP.NIEAN WHERE PRODUCT.CODE IS NOT NULL AND brands.DESC IS NOT NULL UNION ALL SELECT 'unknown' AS BRAND, 'unknown' AS MAIN_GROUP, 'unknown' AS SUB_GROUP, 'unknown' AS SUB_SUB_GROUP, PRODUCT.DESC3, PRODUCT.DESC4, PRODUCT.DESC5, UF_IBARCODE AS NIEAN, PRODUCT.DESC1 AS long_description, PRODUCTDESCLOOKUP.NIBRAND, PRODUCTDESCLOOKUP.NIINGREDS, PRODUCTDESCLOOKUP.NIABV, PRODUCTDESCLOOKUP.NIMANUFNADD, PRODUCTDESCLOOKUP.NIORIGIN, PRODUCTDESCLOOKUP.NISTORAGE, PRODUCTDESCLOOKUP.NISTORAGETYPE, PRODUCTDESCLOOKUP.NINUTRITIONHTML, PRODUCTDESCLOOKUP.NIPREPUSAGE, PRODUCTDESCLOOKUP.NICOOKGUIDE, PRODUCTDESCLOOKUP.NICOOKCONCISE, PRODUCTDESCLOOKUP.unit_net_weight, PRODUCT.CODE, PRODUCT.CUNIT, PRODUCT.CUNITFAC, PRODUCT.UF_IBARCODE, PRODUCT.UF_O_BARCODE, PRODUCT.UF_PRE_PRICED, PRODUCT.MASSNET, PRODUCT.MASSGROSS, PRODUCT.VOL, PRODUCT.COMMOD, PRODUCT.UF_CATCHWT, PRODUCT.UF_CSSPALLET, PRODUCT.UF_CSSLAYER, PRODUCT.UF_BBEROTDATE, PRODUCT.UF_BBEROTDIS, PRODUCT.UF_RRP, PRODUCT.UF_WH_SHELF, PRODUCT.UF_NODISCOUNT, PRODUCT.PRUSER01, PRODUCT.PRUSER02, PRODUCT.PRUSER03, PRODUCT.UF_SUPPLIERSUB, PRODUCT.UF_RIALT1, PRODUCT.UF_RIALT2, PRODUCT.UF_RIALT3, PRODUCT.UF_RIALT4 FROM PRODUCT LEFT JOIN PRODUCTDESCLOOKUP ON PRODUCT.UF_IBARCODE = PRODUCTDESCLOOKUP.NIEAN WHERE PRODUCT.CODE LIKE '*%';

